@* Vertical sidebar navigation for settings sections *@

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="sidebar-nav">
        @foreach (var section in Sections)
        {
            <li class="sidebar-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionSelected.InvokeAsync(section)">
                <span class="sidebar-icon">@GetIcon(section)</span>
                <span class="sidebar-label">@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
    min-height: 100%;
}

.sidebar-title {
    padding: 0 1.25rem;
    margin-bottom: 1rem;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.sidebar-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    color: #495057;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
    font-size: 0.95rem;
}

.sidebar-item:hover {
    background: #e9ecef;
}

.sidebar-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

@using sv_7648a3102fef4c88a0783ae8e9d59fe9.Models

<section class="settings-section">
    <h4>Profile</h4>
    <p class="text-muted">Manage your personal information.</p>

    @if (Profile is null)
    {
        <p>Loading...</p>
        return;
    }

    <div class="profile-form">
        <div class="avatar-area">
            <div class="avatar-preview">
                @if (!string.IsNullOrWhiteSpace(editAvatarUrl))
                {
                    <img src="@editAvatarUrl" alt="Avatar" />
                }
                else
                {
                    <span class="avatar-placeholder">👤</span>
                }
            </div>
            <div class="avatar-url text-muted small">@editAvatarUrl</div>
        </div>

        <div class="form-fields">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="editDisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="editEmail" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="editBio"></textarea>
