@code {
    [Parameter, EditorRequired]
    public NotificationPrefs? Prefs { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool editEmailNotifications;
    private bool editPushNotifications;
    private bool editWeeklyDigest;
    private HashSet<string> editMutedChannels = new();
    private string? statusMessage;
    private bool isError;
    private bool isSaving;

    // Superset of known channels — includes any from current prefs
    private List<string> allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !isSaving)
        {
            editEmailNotifications = Prefs.EmailNotifications;
            editPushNotifications = Prefs.PushNotifications;
            editWeeklyDigest = Prefs.WeeklyDigest;
            editMutedChannels = new HashSet<string>(Prefs.MutedChannels);

            // Merge any extra channels from prefs
            foreach (var ch in Prefs.MutedChannels)
            {
                if (!allChannels.Contains(ch))
                    allChannels.Add(ch);
            }
        }
    }

    private void ToggleChannel(string channel, bool isEnabled)
    {
        if (isEnabled)
            editMutedChannels.Remove(channel);
        else
            editMutedChannels.Add(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                editEmailNotifications,
                editPushNotifications,
                editWeeklyDigest,
                editMutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            statusMessage = "Preferences saved successfully.";
            isError = false;
        }
        catch
        {
            statusMessage = "Failed to save preferences.";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}

