                <strong>Two-Factor Authentication</strong>
                <div class="small mt-1">
                    @if (Settings.TwoFactorEnabled)
                    {
                        <span class="badge bg-success">Enabled</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Disabled</span>
                    }
                </div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       checked="@Settings.TwoFactorEnabled" disabled
                       title="Contact support to change 2FA settings" />
            </div>
        </div>
    </div>

    @if (Settings.LastPasswordChange.HasValue)
    {
        <p class="text-muted small">
            Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    @* Active Sessions *@
    <h5 class="mt-4">Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-hover">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Settings.Sessions)
                {
                    var isCurrent = session == Settings.Sessions.FirstOrDefault();
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-info ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                        <td>
                            @if (!isCurrent)
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => PromptRevoke(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <RevokeSessionDialog Visible="@showRevokeDialog"
                         DeviceName="@(sessionToRevoke?.Device ?? "")"
                         OnConfirm="ConfirmRevokeAsync"
                         OnCancel="CancelRevoke" />
</section>

@code {
    [Parameter, EditorRequired]
    public SecuritySettings? Settings { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(string currentPassword, string newPassword)> OnChangePassword { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevokeSession { get; set; }

    private bool passwordPanelOpen;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? passwordMessage;
    private bool passwordError;
    private bool changingPassword;

    private bool showRevokeDialog;
    private ActiveSession? sessionToRevoke;

    private async Task ChangePasswordAsync()
    {
        passwordMessage = null;
        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            passwordMessage = "All password fields are required.";
            passwordError = true;
            return;
        }
        if (newPassword != confirmPassword)
        {
            passwordMessage = "New passwords do not match.";
            passwordError = true;
            return;
        }

        changingPassword = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            passwordMessage = "Password updated successfully.";
            passwordError = false;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch
        {
            passwordMessage = "Failed to change password.";
            passwordError = true;
        }
        finally
        {
            changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        sessionToRevoke = session;
        showRevokeDialog = true;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(sessionToRevoke.Id);
        }
        showRevokeDialog = false;
        sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        showRevokeDialog = false;
        sessionToRevoke = null;
    }
}

