            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@(!isMuted)"
                       @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") mt-3" role="alert">
            @statusMessage
        </div>
    }

    <div class="mt-3">
