@using sv_7648a3102fef4c88a0783ae8e9d59fe9.Models

<section class="settings-section">
    <h4>Profile</h4>
    <p class="text-muted">Manage your personal information.</p>

    @if (Profile is null)
    {
        <p>Loading...</p>
        return;
    }

    <div class="profile-form">
        <div class="avatar-area">
            <div class="avatar-preview">
                @if (!string.IsNullOrWhiteSpace(editAvatarUrl))
                {
                    <img src="@editAvatarUrl" alt="Avatar" />
                }
                else
                {
                    <span class="avatar-placeholder">👤</span>
                }
            </div>
            <div class="avatar-url text-muted small">@editAvatarUrl</div>
        </div>

        <div class="form-fields">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="editDisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="editEmail" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="editBio"></textarea>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") mt-3" role="alert">
            @statusMessage
        </div>
    }

    <div class="button-row mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@isSaving">
            Discard Changes
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public UserProfile? Profile { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<UserProfile> OnSave { get; set; }

    private string editDisplayName = "";
    private string editEmail = "";
    private string editAvatarUrl = "";
    private string editBio = "";
    private string? statusMessage;
    private bool isError;
    private bool isSaving;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !isSaving)
        {
            ResetFields();
        }
    }

    private void ResetFields()
    {
        editDisplayName = Profile!.DisplayName;
        editEmail = Profile.Email;
        editAvatarUrl = Profile.AvatarUrl;
        editBio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new UserProfile(editDisplayName, editEmail, editAvatarUrl, editBio);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Profile saved successfully.";
            isError = false;
        }
        catch
        {
            statusMessage = "Failed to save profile.";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }

    private void Discard()
    {
        ResetFields();
        statusMessage = null;
    }
}

