toolArgs.file_text:
@using sv_7648a3102fef4c88a0783ae8e9d59fe9.Models

<section class="settings-section">
    <h4>Notifications</h4>
    <p class="text-muted">Choose what updates you receive.</p>

    @if (Prefs is null)
    {
        <p>Loading...</p>
        return;
    }

    <div class="notification-toggles">
        <div class="toggle-row">
            <div>
                <strong>Email Notifications</strong>
                <div class="text-muted small">Receive updates via email</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       checked="@editEmailNotifications"
                       @onchange="e => editEmailNotifications = (bool)e.Value!" />
            </div>
        </div>

        <div class="toggle-row">
            <div>
                <strong>Push Notifications</strong>
                <div class="text-muted small">Receive push notifications in your browser</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       checked="@editPushNotifications"
                       @onchange="e => editPushNotifications = (bool)e.Value!" />
            </div>
        </div>

        <div class="toggle-row">
            <div>
                <strong>Weekly Digest</strong>
                <div class="text-muted small">Get a weekly summary of activity</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       checked="@editWeeklyDigest"
                       @onchange="e => editWeeklyDigest = (bool)e.Value!" />
            </div>
        </div>
    </div>

    <h5 class="mt-4">Muted Channels</h5>
    <p class="text-muted small">Uncheck channels you want to mute.</p>

    <div class="channels-list">
        @foreach (var channel in allChannels)
        {
            var isMuted = editMutedChannels.Contains(channel);
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@(!isMuted)"
                       @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") mt-3" role="alert">
            @statusMessage
        </div>
    }

    <div class="mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save Preferences")
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public NotificationPrefs? Prefs { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool editEmailNotifications;
    private bool editPushNotifications;
    private bool editWeeklyDigest;
    private HashSet<string> editMutedChannels = new();
    private string? statusMessage;
    private bool isError;
    private bool isSaving;

    // Superset of known channels — includes any from current prefs
    private List<string> allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !isSaving)
        {
            editEmailNotifications = Prefs.EmailNotifications;
            editPushNotifications = Prefs.PushNotifications;
            editWeeklyDigest = Prefs.WeeklyDigest;
            editMutedChannels = new HashSet<string>(Prefs.MutedChannels);

            // Merge any extra channels from prefs
            foreach (var ch in Prefs.MutedChannels)
            {
                if (!allChannels.Contains(ch))
                    allChannels.Add(ch);
            }
        }
    }

    private void ToggleChannel(string channel, bool isEnabled)
    {
        if (isEnabled)
            editMutedChannels.Remove(channel);
        else
            editMutedChannels.Add(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                editEmailNotifications,
                editPushNotifications,
                editWeeklyDigest,
                editMutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            statusMessage = "Preferences saved successfully.";
            isError = false;
        }
        catch
        {
            statusMessage = "Failed to save preferences.";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}

