toolArgs.file_text:
@using sv_7648a3102fef4c88a0783ae8e9d59fe9.Models

<section class="settings-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize how the application looks.</p>

    @if (Settings is null)
    {
        <p>Loading...</p>
        return;
    }

    <div class="appearance-grid">
        <div class="appearance-controls">
            @* Theme *@
            <div class="mb-3">
                <label class="form-label fw-semibold">Theme</label>
                <div class="d-flex gap-3">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   checked="@(editTheme == theme)"
                                   @onchange="() => editTheme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            @* Font Size *@
            <div class="mb-3">
                <label class="form-label fw-semibold">Font Size</label>
                <div class="d-flex gap-3">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   checked="@(editFontSize == size)"
                                   @onchange="() => editFontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            @* Language *@
            <div class="mb-3">
                <label class="form-label fw-semibold">Language</label>
                <select class="form-select" style="max-width: 250px;"
                        @bind="editLanguage">
                    <option value="en">English</option>
                    <option value="es">Spanish</option>
                    <option value="fr">French</option>
                    <option value="de">German</option>
                    <option value="ja">Japanese</option>
                    <option value="zh">Chinese</option>
                </select>
            </div>

            @* Compact Mode *@
            <div class="mb-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch" id="compactMode"
                           checked="@editCompactMode"
                           @onchange="e => editCompactMode = (bool)e.Value!" />
                    <label class="form-check-label" for="compactMode">
                        <strong>Compact Mode</strong>
                        <div class="text-muted small">Reduce spacing and padding throughout the app</div>
                    </label>
                </div>
            </div>

            @if (!string.IsNullOrEmpty(statusMessage))
            {
                <div class="alert @(isError ? "alert-danger" : "alert-success") mt-3" role="alert">
                    @statusMessage
                </div>
            }

            <button class="btn btn-primary mt-2" @onclick="SaveAsync" disabled="@isSaving">
                @(isSaving ? "Saving..." : "Save")
            </button>
        </div>

        @* Live Preview *@
        <div class="preview-panel">
            <h6 class="fw-semibold mb-2">Preview</h6>
            <div class="preview-box @PreviewThemeClass" style="font-size: @PreviewFontSizeCss; padding: @(editCompactMode ? "0.5rem" : "1rem");">
                <div class="preview-header">Dashboard</div>
                <p class="preview-text">
                    This is how your content will look with the selected settings.
                </p>
                <div class="preview-card">
                    <strong>Sample Card</strong>
                    <p class="mb-0">Theme: @editTheme · Font: @editFontSize · @(editCompactMode ? "Compact" : "Normal")</p>
                </div>
                <button class="btn btn-sm @(editTheme == "Dark" ? "btn-light" : "btn-primary") mt-2">
                    Sample Button
                </button>
            </div>
        </div>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public AppearanceSettings? Settings { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string editTheme = "Light";
    private string editFontSize = "Medium";
    private string editLanguage = "en";
    private bool editCompactMode;
    private string? statusMessage;
    private bool isError;
    private bool isSaving;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !isSaving)
        {
            editTheme = Settings.Theme;
            editFontSize = Settings.FontSize;
            editLanguage = Settings.Language;
            editCompactMode = Settings.CompactMode;
        }
    }

    private string PreviewThemeClass => editTheme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string PreviewFontSizeCss => editFontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private async Task SaveAsync()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(editTheme, editFontSize, editLanguage, editCompactMode);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Appearance saved successfully.";
            isError = false;
        }
        catch
        {
            statusMessage = "Failed to save appearance settings.";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}

.appearance-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 2rem;
    align-items: start;
}

.preview-panel {
    position: sticky;
    top: 1rem;
}

.preview-box {
    border-radius: 8px;
    border: 1px solid #dee2e6;
    transition: all 0.2s ease;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-header {
    font-weight: 700;
    font-size: 1.1em;
    margin-bottom: 0.5rem;
}

.preview-text {
    margin-bottom: 0.75rem;
    opacity: 0.8;
}

.preview-card {
    border-radius: 6px;
    padding: 0.75rem;
    border: 1px solid rgba(128, 128, 128, 0.3);
}

.preview-light .preview-card {
    background: #f8f9fa;
}

.preview-dark .preview-card {
    background: #2a2a3d;
}

@media (max-width: 768px) {
    .appearance-grid {
        grid-template-columns: 1fr;
    }
}

