@page "/settings"
@using sv_7648a3102fef4c88a0783ae8e9d59fe9.Models
@using sv_7648a3102fef4c88a0783ae8e9d59fe9.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@activeSection"
                     OnSectionSelected="section => activeSection = section" />

    <div class="settings-content">
        @switch (activeSection)
        {
            case "Profile":
                <ProfileSection Profile="@profile" OnSave="SaveProfileAsync" />
